#include <bits/stdc++.h>
using namespace std;
#define ll long long
ll n,m,tr[400005],tab[400005];
void push_down(ll u,ll l,ll r)
{
	ll ls=u*2,rs=u*2+1,mid=(l+r)>>1;
	tr[ls]+=(tab[u]*(mid-l+1));
	tab[ls]+=tab[u];
	tr[rs]+=(tab[u]*(r-mid));
	tab[rs]+=tab[u];
	tab[u]=0;
}
void add(ll u,ll l,ll r,ll x,ll y,ll k)
{
	if(l>y||r<x) return ;
	if(l>=x&&r<=y)
	{
		tr[u]+=(k*(r-l+1));
		tab[u]+=k;
		return ;
	}
	ll mid=(l+r)>>1;
	push_down(u,l,r);
	add(u*2,l,mid,x,y,k);
	add(u*2+1,mid+1,r,x,y,k);
	tr[u]=tr[u*2]+tr[u*2+1];
}
ll sum(ll u,ll l,ll r,ll x,ll y)
{
	if(l>y||r<x) return 0;
	if(l>=x&&r<=y) return tr[u];
	push_down(u,l,r);
	ll mid=(l+r)>>1;
	return sum(u*2,l,mid,x,y)+sum(u*2+1,mid+1,r,x,y);
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(ll i=1;i<=n;i++)
	{
		ll k;
		cin>>k;
		add(1,1,n,i,i,k);
	}
	while(m--)
	{
		ll op;
		cin>>op;
		if(op==1)
		{
			ll x,y,k;
			cin>>x>>y>>k;
			add(1,1,n,x,y,k);
		}
		else
		{
			ll x,y;
			cin>>x>>y;
			cout<<sum(1,1,n,x,y)<<'\n';
		}
	}
	return 0;
}
